package policy

import (
	"bytes"
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/policy/types"
)

func TestPolicyAuditLoggerCreation(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)
	assert.Equal(t, logrus.InfoLevel, logger.GetLogLevel())
}

func TestLogDecision(t *testing.T) {
	// Create a logger with debug level
	logger := NewPolicyAuditLogger(logrus.DebugLevel)
	require.NotNil(t, logger)

	// Set up a buffer to capture log output
	var buf bytes.Buffer
	logger.scopedLog.Logger.SetOutput(&buf)
	logger.scopedLog.Logger.SetLevel(logrus.DebugLevel)

	// Log a decision
	testIdentity := identity.NumericIdentity(1234)
	testPolicy := "test-policy"
	testVerdict := "ALLOW"
	testReason := "matched selector"

	logger.LogDecision(testIdentity, testPolicy, testVerdict, testReason)

	// Verify the decision was logged
	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "Policy decision logged")
	assert.Contains(t, output, testPolicy)
	assert.Contains(t, output, testVerdict)
}

func TestLogDecisionDeny(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	var buf bytes.Buffer
	logger.scopedLog.Logger.SetOutput(&buf)
	logger.scopedLog.Logger.SetLevel(logrus.InfoLevel)

	testIdentity := identity.NumericIdentity(5678)
	testPolicy := "deny-policy"
	testVerdict := "DENY"
	testReason := "no matching rule"

	logger.LogDecision(testIdentity, testPolicy, testVerdict, testReason)

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, testVerdict)
}

func TestLogEvaluation(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.DebugLevel)
	require.NotNil(t, logger)

	var buf bytes.Buffer
	logger.scopedLog.Logger.SetOutput(&buf)
	logger.scopedLog.Logger.SetLevel(logrus.DebugLevel)

	// Create a test policy key
	policyKey := types.Key{
		Identity:         1000,
		DestPort:         8080,
		InvertedPortMask: 0xffff,
		Nexthdr:          6, // TCP
		TrafficDirection: 0, // Ingress
	}

	// Create a test result
	result := map[string]interface{}{
		"allowed": true,
		"reason":  "policy matched",
	}

	ctx := context.Background()
	logger.LogEvaluation(ctx, policyKey, nil, result)

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "Policy evaluation completed")
	assert.Contains(t, output, "8080")
}

func TestSetAndGetLogLevel(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	assert.Equal(t, logrus.InfoLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.DebugLevel)
	assert.Equal(t, logrus.DebugLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.WarnLevel)
	assert.Equal(t, logrus.WarnLevel, logger.GetLogLevel())
}

func TestLogDecisionThreadSafety(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	var buf bytes.Buffer
	logger.scopedLog.Logger.SetOutput(&buf)
	logger.scopedLog.Logger.SetLevel(logrus.InfoLevel)

	// Test concurrent access to LogDecision
	done := make(chan bool)
	for i := 0; i < 10; i++ {
		go func(idx int) {
			testID := identity.NumericIdentity(1000 + idx)
			logger.LogDecision(testID, "policy", "ALLOW", "reason")
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}

	// Verify no crashes and output was generated
	output := buf.String()
	assert.NotEmpty(t, output)
}

func TestLogEvaluationWithComplexResult(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.DebugLevel)
	require.NotNil(t, logger)

	var buf bytes.Buffer
	logger.scopedLog.Logger.SetOutput(&buf)
	logger.scopedLog.Logger.SetLevel(logrus.DebugLevel)

	policyKey := types.Key{
		Identity:         2000,
		DestPort:         443,
		InvertedPortMask: 0,
		Nexthdr:          6,
		TrafficDirection: 1,
	}

	// Complex nested result structure
	result := map[string]interface{}{
		"allowed": true,
		"selectors": []string{
			"app=web",
			"tier=frontend",
		},
		"metadata": map[string]interface{}{
			"rule_count": 5,
			"match_type": "label-selector",
		},
	}

	ctx := context.Background()
	logger.LogEvaluation(ctx, policyKey, nil, result)

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "2000")
	assert.Contains(t, output, "443")
}

